// Arma el body del pedido a OpenAI y preserva info del mensaje.
// Tolera mensajes sin texto (sticker/foto/voz) — responde con help.
const msg = $json.message || {};
const userText = (msg.text || '').trim();
const chat_id = msg.chat && msg.chat.id;

const systemPrompt = [
  'Sos un asistente para el admin de Party House.',
  'Extraé del mensaje el nombre del invitado que el admin quiere crear.',
  'Si el mensaje incluye "invitado especial" o "especial", ese invitado no paga (special_guest: true).',
  'NO pidas ni proceses email ni número de teléfono — esos datos se capturan después.',
  'Responde SIEMPRE con JSON puro, sin markdown. Usá uno de estos 3 formatos:',
  '1) Si hay datos suficientes (al menos first_name y last_name):',
  '   {"action":"create_code","first_name":"...","last_name":"...","special_guest":false}',
  '   Si es invitado especial:',
  '   {"action":"create_code","first_name":"...","last_name":"...","special_guest":true}',
  '2) Si falta información (nombre completo):',
  '   {"action":"ask","message":"Pedile al usuario lo que falta"}',
  '3) Si el mensaje no es una orden válida:',
  '   {"action":"help","message":"Ejemplo: crea código para Juan Pérez / invitado especial María López"}'
].join('\n');

const body = {
  model: 'gpt-4o-mini',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userText || 'hola' }
  ]
};

return [{ json: { chat_id, userText, openai_body: body } }];

// Parsea la respuesta de OpenAI y construye el código en nuevo formato:
// 2 iniciales (primer letra nombre + primer letra apellido) + 3 dígitos (100-999)
// Ejemplo: Juan Pérez → JP482
const EVENT_ID = 'bdf59dc5-a260-4be9-99b4-81450982c8d6';

const prepItems = $items('Preparar pedido OpenAI');
const prep = (prepItems && prepItems[0] && prepItems[0].json) || {};
const chat_id = prep.chat_id;

let aiContent = '';
try {
  aiContent = $json.choices && $json.choices[0] && $json.choices[0].message
    ? $json.choices[0].message.content
    : '';
} catch (e) {
  aiContent = '';
}

let ai = {};
try { ai = JSON.parse(aiContent || '{}'); }
catch (e) {
  ai = { action: 'help', message: 'No pude entender. Probá: "crea código para Juan Pérez" o "invitado especial María López"' };
}

if (ai.action !== 'create_code' || !ai.first_name) {
  const helpMsg = ai.message || 'No entendí. Probá: "crea código para Juan Pérez"';
  return [{ json: { needs_reply: true, chat_id, text: helpMsg } }];
}

// Nuevo formato: 2 iniciales + 3 dígitos (100-999)
const clean = (s) => String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^A-Za-z]/g, '').toUpperCase();
const firstInitial = clean(ai.first_name).charAt(0) || 'G';
const lastInitial  = clean(ai.last_name || '').charAt(0) || 'X';
const digits       = String(Math.floor(Math.random() * 900) + 100); // 100-999
const code         = firstInitial + lastInitial + digits;

return [{ json: {
  needs_reply:   false,
  chat_id,
  first_name:    ai.first_name,
  last_name:     ai.last_name || '',
  event_id:      EVENT_ID,
  code,
  special_guest: ai.special_guest === true
}}];

